    public record TimestampEntry(
        long ts,
        String event,
        byte[] payload
    ) {}

    public static void writeTimestampEntry(SpecWriter w, TimestampEntry obj) {
        int fieldCount = 2;
        if (obj.payload() != null) fieldCount++;
        w.beginObject(fieldCount);
        w.writeField("ts"); w.writeInt64(obj.ts());
        w.writeField("event"); w.writeString(obj.event());
        if (obj.payload() != null) { w.writeField("payload"); w.writeBytes(obj.payload()); }
        w.endObject();
    }

    public static final SpecCodec<TimestampEntry> TimestampEntryCodec = new SpecCodec<>(
        (w, obj) -> writeTimestampEntry(w, (TimestampEntry) obj),
        r -> readTimestampEntry(r)
    );

    public static TimestampEntry readTimestampEntry(SpecReader r) {
        long tsVal = 0L;
        String eventVal = "";
        byte[] payloadVal = null;
        r.beginObject();
        while (r.hasNextField()) {
            switch (r.readFieldName()) {
                case "ts":
                    tsVal = r.readInt64();
                    break;
                case "event":
                    eventVal = r.readString();
                    break;
                case "payload":
                    payloadVal = r.readBytes();
                    break;
                default: r.skip(); break;
            }
        }
        r.endObject();
        return new TimestampEntry(tsVal, eventVal, payloadVal);
    }

    public record ConfigEntry(
        String key,
        Integer intValue,
        String strValue,
        Boolean boolValue,
        Double floatValue
    ) {}

    public static void writeConfigEntry(SpecWriter w, ConfigEntry obj) {
        int fieldCount = 1;
        if (obj.intValue() != null) fieldCount++;
        if (obj.strValue() != null) fieldCount++;
        if (obj.boolValue() != null) fieldCount++;
        if (obj.floatValue() != null) fieldCount++;
        w.beginObject(fieldCount);
        w.writeField("key"); w.writeString(obj.key());
        if (obj.intValue() != null) { w.writeField("intValue"); w.writeInt32(obj.intValue()); }
        if (obj.strValue() != null) { w.writeField("strValue"); w.writeString(obj.strValue()); }
        if (obj.boolValue() != null) { w.writeField("boolValue"); w.writeBool(obj.boolValue()); }
        if (obj.floatValue() != null) { w.writeField("floatValue"); w.writeFloat64(obj.floatValue()); }
        w.endObject();
    }

    public static final SpecCodec<ConfigEntry> ConfigEntryCodec = new SpecCodec<>(
        (w, obj) -> writeConfigEntry(w, (ConfigEntry) obj),
        r -> readConfigEntry(r)
    );

    public static ConfigEntry readConfigEntry(SpecReader r) {
        String keyVal = "";
        Integer intValueVal = null;
        String strValueVal = null;
        Boolean boolValueVal = null;
        Double floatValueVal = null;
        r.beginObject();
        while (r.hasNextField()) {
            switch (r.readFieldName()) {
                case "key":
                    keyVal = r.readString();
                    break;
                case "intValue":
                    intValueVal = r.readInt32();
                    break;
                case "strValue":
                    strValueVal = r.readString();
                    break;
                case "boolValue":
                    boolValueVal = r.readBool();
                    break;
                case "floatValue":
                    floatValueVal = r.readFloat64();
                    break;
                default: r.skip(); break;
            }
        }
        r.endObject();
        return new ConfigEntry(keyVal, intValueVal, strValueVal, boolValueVal, floatValueVal);
    }

